    private static let anxiety = [
        lesson("anx-01", "Understand the alarm", "Alarm is not always danger", "Anxiety can activate a real protective response even when no immediate threat is present. The sensations are real; the prediction attached to them may still need checking.", "Name the sensation, then name the observable situation separately.", "NIMH · Anxiety disorders", "https://www.nimh.nih.gov/health/topics/anxiety-disorders"),
        lesson("anx-02", "Understand the alarm", "Panic has a body pattern", "Panic attacks can involve racing heart, dizziness, trembling, chest discomfort, breathlessness, and fear of losing control. New or unusual physical symptoms still deserve appropriate medical assessment.", "Write the sensations you notice without adding what you fear they mean.", "NIMH · Panic disorder", "https://www.nimh.nih.gov/health/publications/panic-disorder-when-fear-overwhelms"),
        lesson("anx-03", "Understand the alarm", "Anxiety is broader than worry", "Anxiety disorders include several patterns, such as generalized anxiety, panic, social anxiety, and phobias. A qualified clinician looks at duration, impairment, context, and other possible causes.", "Notice which situations, body sensations, or uncertainties most reliably start your pattern.", "NIMH · Anxiety disorders", "https://www.nimh.nih.gov/health/topics/anxiety-disorders"),
        lesson("anx-04", "Understand the alarm", "A symptom is not a diagnosis", "Sleep loss, substances, medications, thyroid problems, heart or breathing conditions, and other factors can overlap with anxiety symptoms. Self-help works best alongside assessment when symptoms are persistent or changing.", "List anything medical, sleep-related, or substance-related worth discussing with a clinician.", "NIMH · Anxiety disorders", "https://www.nimh.nih.gov/health/topics/anxiety-disorders"),
        lesson("anx-05", "Change the learning", "Avoidance teaches fear to stay", "Avoidance can bring fast relief, which may reinforce the belief that escape prevented catastrophe. Supported, gradual approach practice can create different learning.", "Choose the smallest safe version of one avoided situation and repeat it before increasing difficulty.", "NIMH · Psychotherapies", "https://www.nimh.nih.gov/health/topics/psychotherapies"),
        lesson("anx-06", "Change the learning", "Exposure is planned, not reckless", "Evidence-based exposure is collaborative and gradual. It is not forcing someone into danger, ignoring consent, or flooding the nervous system to prove toughness.", "Create a five-step ladder from mildly uncomfortable to difficult, and start near the bottom.", "NIMH · Psychotherapies", "https://www.nimh.nih.gov/health/topics/psychotherapies"),
        lesson("anx-07", "Change the learning", "Safety behaviors can hide progress", "Repeatedly checking, seeking certainty, or carrying a special escape may make it hard to learn that a situation can be tolerated without those protections. Safety needs and compulsive reassurance are not the same thing.", "Reduce one unnecessary reassurance behavior slightly while keeping genuine safety intact.", "NHS · CBT overview", "https://www.nhs.uk/mental-health/talking-therapies-medicine-treatments/talking-therapies-and-counselling/cognitive-behavioural-therapy-cbt/overview/"),
        lesson("anx-08", "Change the learning", "Measure approach, not calm", "The goal of practice is not to guarantee zero anxiety. A more useful measure is whether you stayed, learned, and acted according to your values while discomfort changed on its own timeline.", "After a practice, record what you approached and what you learned rather than only your anxiety score.", "NIMH · Psychotherapies", "https://www.nimh.nih.gov/health/topics/psychotherapies"),
        lesson("anx-09", "Work with thoughts", "CBT asks for accuracy", "Cognitive behavioral therapy does not require cheerful thoughts. It examines whether a conclusion is complete, supported, and useful enough to guide action.", "Write the prediction, evidence for it, evidence against it, and the most balanced conclusion.", "NHS · CBT overview", "https://www.nhs.uk/mental-health/talking-therapies-medicine-treatments/talking-therapies-and-counselling/cognitive-behavioural-therapy-cbt/overview/"),
        lesson("anx-10", "Work with thoughts", "Uncertainty cannot be eliminated", "Anxiety often demands a guarantee before action. Repeated checking can temporarily soothe that demand while teaching the mind that uncertainty itself is unsafe.", "Choose one low-risk decision and allow it to remain good enough without another check.", "NIMH · Anxiety disorders", "https://www.nimh.nih.gov/health/topics/anxiety-disorders"),
        lesson("anx-11", "Work with the body", "Bigger breaths are not always better", "Rapid or oversized breathing can intensify tingling, dizziness, and air hunger. A slower, comfortable, normal-size breath may be more useful than repeatedly trying to fill the lungs.", "Breathe gently in for four and out for six; stop and return to natural breathing if symptoms worsen.", "VA · Breathing guidance", "https://www.ptsd.va.gov/PTSD/disaster_events/for_providers/spr/docs/SPR02_Breathing.pdf"),
        lesson("anx-12", "Work with the body", "Grounding restores context", "Grounding directs attention toward present sensory information when the mind is absorbed in a feared future. It is a way to orient, not a test you can fail.", "Name three shapes, two sounds, and one point of physical support.", "VA · Mindful awareness", "https://www.va.gov/WHOLEHEALTHLIBRARY/tools/diaphragmatic-breathing.asp"),
        lesson("anx-13", "Work with the body", "Relaxation is optional", "Relaxation techniques are generally safe, but some people report increased anxiety, intrusive thoughts, or loss-of-control fears. Choice, open eyes, movement, and shorter practice can matter.", "If stillness feels worse, try a slow walk while naming what you see.", "NCCIH · Relaxation safety", "https://www.nccih.nih.gov/health/relaxation-techniques-what-you-need-to-know"),
        lesson("anx-14", "Build the foundation", "Sleep can change the volume", "Sleep and emotional regulation influence each other. A consistent schedule and enough opportunity for sleep can support coping, though sleep habits alone do not treat every anxiety disorder.", "Protect a repeatable wake time for the next three days.", "NHLBI · Healthy sleep", "https://www.nhlbi.nih.gov/health/sleep-deprivation/healthy-sleep-habits"),
        lesson("anx-15", "Build the foundation", "Movement can support care", "Regular physical activity supports physical and mental health. It can complement treatment, but a workout should not become punishment or a demand to erase anxiety immediately.", "Choose ten comfortable minutes of movement you can repeat this week.", "CDC · Physical activity", "https://www.cdc.gov/physical-activity/php/about/index.html"),
        lesson("anx-16", "Treatment and support", "Effective treatment can be combined", "Psychotherapy, medication, or both may be used depending on the person, the anxiety pattern, preferences, other conditions, and access. Finding the right fit can take adjustment.", "Write three questions you want to ask a licensed clinician about options and side effects.", "NIMH · Anxiety disorders", "https://www.nimh.nih.gov/health/topics/anxiety-disorders"),
        lesson("anx-17", "Treatment and support", "Track patterns, not perfection", "A brief log of trigger, body response, thought, action, and outcome can reveal what keeps the cycle going. Tracking should clarify care, not become another compulsion.", "Log one episode in five lines, then close the note.", "NHS · CBT overview", "https://www.nhs.uk/mental-health/talking-therapies-medicine-treatments/talking-therapies-and-counselling/cognitive-behavioural-therapy-cbt/overview/"),
        lesson("anx-18", "Treatment and support", "Know when self-help is not enough", "Persistent impairment, fainting, severe chest pain, new neurologic symptoms, substance withdrawal, or thoughts of self-harm need professional or urgent support rather than another breathing exercise.", "Save the contact for your clinician, local urgent care, and crisis support before you need it.", "NIMH · Find help", "https://www.nimh.nih.gov/health/find-help"),
    ]

    private static let depression = [
        lesson("dep-01", "Understand the pattern", "Depression is more than sadness", "Depression can affect mood, interest, energy, concentration, sleep, appetite, movement, guilt, and hope. Diagnosis considers the pattern, duration, impairment, and other causes.", "Describe what changed in behavior and function, not only how bad you feel.", "NIMH · Depression", "https://www.nimh.nih.gov/health/topics/depression"),
        lesson("dep-02", "Understand the pattern", "The future can look falsely permanent", "Depression can make a current state feel global and endless. That feeling is important information, but it is not reliable proof about every future day.", "Replace always and never with a dated, specific description of today.", "NIMH · Depression", "https://www.nimh.nih.gov/health/topics/depression"),
        lesson("dep-03", "Behavioral activation", "Action can come before motivation", "Low mood can reduce activity, reward, mastery, and connection. Behavioral approaches schedule small meaningful actions instead of waiting for motivation to arrive first.", "Choose one five-minute action connected to care, mastery, or connection.", "NIMH · Psychotherapies", "https://www.nimh.nih.gov/health/topics/psychotherapies"),
        lesson("dep-04", "Behavioral activation", "Make the action observable", "Vague goals such as be productive are hard to begin and hard to learn from. A useful plan identifies what, where, and when.", "Rewrite one goal as: At this time, in this place, I will do this for five minutes.", "NIMH · Psychotherapies", "https://www.nimh.nih.gov/health/topics/psychotherapies"),
        lesson("dep-05", "Thinking skills", "A thought is a mental event", "Depressive conclusions can feel complete while leaving out context, exceptions, and available support. CBT tests a thought rather than treating every thought as a command.", "Write one painful thought and one more specific statement that includes what remains changeable.", "NHS · CBT overview", "https://www.nhs.uk/mental-health/talking-therapies-medicine-treatments/talking-therapies-and-counselling/cognitive-behavioural-therapy-cbt/overview/"),
        lesson("dep-06", "Daily foundation", "Regularity reduces extra friction", "A modest rhythm for waking, meals, medication as prescribed, movement, and contact can reduce the number of decisions a low-energy brain must make.", "Anchor tomorrow with one wake cue and one planned meal.", "NIMH · Caring for mental health", "https://www.nimh.nih.gov/health/topics/caring-for-your-mental-health"),
        lesson("dep-07", "Daily foundation", "Connection can be low pressure", "Support does not require a perfect explanation. A short check-in, shared task, or request for company can interrupt isolation.", "Send: I am having a low day. No fixing needed. Can you check in later?", "NIMH · Caring for mental health", "https://www.nimh.nih.gov/health/topics/caring-for-your-mental-health"),
        lesson("dep-08", "Daily foundation", "Movement is support, not a moral test", "Physical activity can support health and mood, but depression may make initiation difficult. Choose an amount gentle enough that tomorrow still feels possible, and never use movement as punishment.", "Walk or stretch for five minutes, then notice whether continuing would feel caring or compulsory.", "CDC · Physical activity", "https://www.cdc.gov/physical-activity/php/about/index.html"),
        lesson("dep-09", "Treatment", "Treatment is adjustable", "Depression treatment can include psychotherapy, medication, brain stimulation therapies, lifestyle support, or combinations. Response and side effects should be reviewed with a qualified clinician.", "Track changes you want to discuss rather than stopping prescribed treatment on your own.", "NIMH · Depression", "https://www.nimh.nih.gov/health/topics/depression"),
        lesson("dep-10", "Treatment", "Physical health belongs in the picture", "Some medical conditions, medications, sleep disorders, and substances can contribute to depressive symptoms. A full assessment is more useful than assuming every symptom has one cause.", "List recent health, medication, sleep, or substance changes for your next appointment.", "NIMH · Depression", "https://www.nimh.nih.gov/health/topics/depression"),
        lesson("dep-11", "Maintenance", "A relapse plan is made while steadier", "Early warning signs can include sleep changes, withdrawal, missed care, rumination, and loss of routine. A written response plan makes support easier to activate.", "Name three warning signs and the first person you will contact.", "NIMH · Depression", "https://www.nimh.nih.gov/health/topics/depression"),
        lesson("dep-12", "Safety", "Hopelessness needs a human response", "Thoughts of death, self-harm, or being unable to stay safe require immediate human support. The app cannot provide emergency care.", "In the U.S. or Canada, call or text 988; in immediate danger, call emergency services.", "NIMH · Find help", "https://www.nimh.nih.gov/health/find-help"),
    ]

    private static let addiction = [
