    private static let growth = [
        lesson("gro-01", "Direction", "Values are practiced directions", "A goal can be completed; a value describes how you want to keep acting. Values help when results are delayed or outside your control.", "Complete: Today I can practice being ___ by doing ___.", "NIMH · Psychotherapies", "https://www.nimh.nih.gov/health/topics/psychotherapies"),
        lesson("gro-02", "Direction", "Fewer priorities create depth", "Attention is limited. Treating every desire as urgent scatters effort and makes feedback hard to read.", "Choose one important action for today and move the rest to a later list.", "NIMH · Caring for mental health", "https://www.nimh.nih.gov/health/topics/caring-for-your-mental-health"),
        lesson("gro-03", "Habits", "Environment carries behavior", "Cues, friction, timing, and access shape repeated action. Good design lowers how often a difficult decision must be remade.", "Make the useful action visible and the distracting action one step harder.", "NIMH · Caring for mental health", "https://www.nimh.nih.gov/health/topics/caring-for-your-mental-health"),
        lesson("gro-04", "Habits", "A minimum protects continuity", "All-or-nothing rules turn a partial success into a total failure. A small minimum keeps the behavior available on difficult days.", "Define the two-minute version of one habit.", "NIMH · Psychotherapies", "https://www.nimh.nih.gov/health/topics/psychotherapies"),
        lesson("gro-05", "Habits", "Tracking should answer a question", "Measurement is useful when it clarifies whether a behavior happened or a pattern is changing. Tracking everything can become avoidance disguised as control.", "Track one behavior for seven days and decide what the data will help you choose.", "CDC · Health behavior", "https://www.cdc.gov/healthyyouth/evaluation/pdf/brief4.pdf"),
        lesson("gro-06", "Learning", "Feedback is not identity", "A result describes what happened under certain conditions. It does not describe the total worth or fixed potential of the person.", "Write what the result suggests changing next time without using a character insult.", "APA · Resilience", "https://www.apa.org/topics/resilience"),
        lesson("gro-07", "Learning", "Practice needs recovery", "Learning and performance are affected by sleep, stress, and recovery. More effort is not always more adaptation.", "Protect one period of rest before adding another demand.", "NHLBI · Sleep and health", "https://www.nhlbi.nih.gov/health/sleep-deprivation"),
        lesson("gro-08", "Learning", "Reflection must return to action", "Review can reveal patterns, but endless self-analysis can become another way to postpone an uncertain step.", "End today's reflection with one action under ten minutes.", "NIMH · Caring for mental health", "https://www.nimh.nih.gov/health/topics/caring-for-your-mental-health"),
        lesson("gro-09", "Support", "Accountability needs dignity", "Useful accountability makes the next action clearer and safer. Humiliation may produce compliance without durable learning.", "Ask someone to check one specific commitment at one specific time.", "APA · Behavior", "https://www.apa.org/topics/behavioral-health"),
        lesson("gro-10", "Support", "Change is allowed to be ordinary", "Sustainable growth often looks repetitive: sleep, meals, focused work, repair, and return. Drama is not evidence of depth.", "Keep one unglamorous promise today and record it once.", "NIMH · Caring for mental health", "https://www.nimh.nih.gov/health/topics/caring-for-your-mental-health"),
    ]

